if (! function_exists('csv_to_sqlite')) {
    function csv_to_sqlite($csv_content, $db_name = null, $table_name = null, $has_headers = null, $delimiter = null, $drop_existing = null, $max_rows = null)
    {
        $csv_content = $csv_content ?? '';
        $db_name = $db_name ?? 'imported_data.sqlite';
        $table_name = $table_name ?? 'csv_data';
        $has_headers = $has_headers ?? true;
        $delimiter = $delimiter ?? ',';
        $drop_existing = $drop_existing ?? false;
        $max_rows = (int)($max_rows ?? 0);

        if (empty(trim($csv_content))) {
            return ['success' => false, 'error' => 'CSV content is required.'];
        }
        if ($max_rows < 0) $max_rows = 0;

        // Parse CSV
        $lines = explode("\n", str_replace("\r\n", "\n", $csv_content));
        if (count($lines) < 1) {
            return ['success' => false, 'error' => 'CSV content is empty or malformed.'];
        }

        $parse_row = function($line) use ($delimiter) {
            // Simple CSV parsing — handles quoted fields
            $fields = [];
            $field = '';
            $in_quotes = false;
            $len = strlen($line);
            for ($i = 0; $i < $len; $i++) {
                $ch = $line[$i];
                if ($in_quotes) {
                    if ($ch === '"') {
                        if ($i + 1 < $len && $line[$i + 1] === '"') {
                            $field .= '"';
                            $i++;
                        } else {
                            $in_quotes = false;
                        }
                    } else {
                        $field .= $ch;
                    }
                } else {
                    if ($ch === '"') {
                        $in_quotes = true;
                    } elseif ($ch === $delimiter) {
                        $fields[] = $field;
                        $field = '';
                    } else {
                        $field .= $ch;
                    }
                }
            }
            $fields[] = $field;
            return $fields;
        };

        $first_line = rtrim($lines[0]);
        $headers = $parse_row($first_line);

        $data_start = $has_headers ? 1 : 0;
        $column_count = count($headers);

        if ($column_count === 0) {
            return ['success' => false, 'error' => 'No columns found in CSV.'];
        }

        // If no headers, generate column names
        if (!$has_headers) {
            $headers = array_map(fn($i) => 'column_' . ($i + 1), range(0, $column_count - 1));
        }

        // Sanitize column names for SQLite
        $safe_headers = array_map(function($h) {
            $h = preg_replace('/[^a-zA-Z0-9_]/', '_', trim($h));
            if (empty($h) || is_numeric($h[0])) $h = 'col_' . $h;
            return strtolower($h);
        }, $headers);

        // Ensure unique names
        $seen = [];
        foreach ($safe_headers as $i => $h) {
            $orig = $h;
            $counter = 1;
            while (in_array($h, $seen)) {
                $h = $orig . '_' . $counter;
                $counter++;
            }
            $seen[] = $h;
            $safe_headers[$i] = $h;
        }

        // Parse all data rows and detect types
        $data_rows = [];
        $type_samples = array_fill(0, $column_count, []);

        $row_count = 0;
        for ($l = $data_start; $l < count($lines); $l++) {
            $line = rtrim($lines[$l]);
            if (empty($line)) continue;
            if ($max_rows > 0 && $row_count >= $max_rows) break;
            
            $fields = $parse_row($line);
            if (count($fields) < 1) continue;
            
            // Pad or trim to match headers
            while (count($fields) < $column_count) $fields[] = '';
            $fields = array_slice($fields, 0, $column_count);
            
            $data_rows[] = $fields;
            $row_count++;
            
            // Sample for type detection (first 20 rows)
            if ($row_count <= 20) {
                for ($c = 0; $c < $column_count; $c++) {
                    $type_samples[$c][] = $fields[$c];
                }
            }
        }

        // Detect column types
        $detect_type = function($samples) {
            $all_empty = true;
            $all_int = true;
            $all_float = true;
            
            foreach ($samples as $v) {
                $v = trim($v);
                if ($v === '') continue;
                $all_empty = false;
                
                if (!is_numeric($v)) { $all_int = false; $all_float = false; break; }
                if (!preg_match('/^-?\d+$/', $v)) $all_int = false;
            }
            
            if ($all_empty) return 'TEXT';
            if ($all_int) return 'INTEGER';
            if ($all_float) return 'REAL';
            return 'TEXT';
        };

        $column_types = [];
        for ($c = 0; $c < $column_count; $c++) {
            $column_types[] = $detect_type($type_samples[$c]);
        }

        // Build CREATE TABLE
        $col_defs = [];
        foreach ($safe_headers as $i => $name) {
            $col_defs[] = '"' . $name . '" ' . $column_types[$i];
        }
        $create_sql = 'CREATE TABLE "' . $table_name . '" (' . implode(', ', $col_defs) . ')';

        // Set up SQLite
        $workspace = __DIR__ . '/../workspace';
        if (!is_dir($workspace)) {
            mkdir($workspace, 0755, true);
        }
        $db_path = $workspace . '/' . $db_name;

        try {
            $pdo = new PDO("sqlite:$db_path");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            
            if ($drop_existing) {
                $pdo->exec('DROP TABLE IF EXISTS "' . $table_name . '"');
            }
            
            $pdo->exec($create_sql);
            
            // Insert data
            $placeholders = implode(',', array_fill(0, $column_count, '?'));
            $insert_sql = 'INSERT INTO "' . $table_name . '" VALUES (' . $placeholders . ')';
            $stmt = $pdo->prepare($insert_sql);
            
            $inserted = 0;
            $pdo->exec('BEGIN TRANSACTION');
            foreach ($data_rows as $row) {
                $typed_row = [];
                for ($c = 0; $c < $column_count; $c++) {
                    $val = trim($row[$c]);
                    if ($val === '') {
                        $typed_row[] = null;
                    } elseif ($column_types[$c] === 'INTEGER') {
                        $typed_row[] = (int)$val;
                    } elseif ($column_types[$c] === 'REAL') {
                        $typed_row[] = (float)$val;
                    } else {
                        $typed_row[] = $val;
                    }
                }
                $stmt->execute($typed_row);
                $inserted++;
            }
            $pdo->exec('COMMIT');
            
            // Verify
            $total = $pdo->query('SELECT COUNT(*) FROM "' . $table_name . '"')->fetchColumn();
            
            return [
                'success' => true,
                'database' => $db_path,
                'db_name' => $db_name,
                'table' => $table_name,
                'columns' => count($safe_headers),
                'column_names' => $safe_headers,
                'column_types' => $column_types,
                'rows_parsed' => $row_count,
                'rows_inserted' => $inserted,
                'rows_in_table' => (int)$total,
                'create_sql' => $create_sql,
            ];
            
        } catch (Exception $e) {
            return ['success' => false, 'error' => 'SQLite error: ' . $e->getMessage()];
        }
    }
